27	/**
28	 * A UTXO entry.
29	 *
30	 * Serialized format:
31	 * - VARINT((height << 1) | (coinbase ? 1 : 0))
32	 * - the non-spent CTxOut (via TxOutCompression)
33	 */
34	class Coin
35	{
36	public:
37	    //! unspent transaction output
38	    CTxOut out;
39	
40	    //! whether containing transaction was a coinbase
41	    bool fCoinBase : 1;
42	
43	    //! at which height this containing transaction was included in the active block chain
44	    uint32_t nHeight : 31;
45	
46	    //! construct a Coin from a CTxOut and height/coinbase information.
47	    Coin(CTxOut&& outIn, int nHeightIn, bool fCoinBaseIn) : out(std::move(outIn)), fCoinBase(fCoinBaseIn), nHeight(nHeightIn) {}
48	    Coin(const CTxOut& outIn, int nHeightIn, bool fCoinBaseIn) : out(outIn), fCoinBase(fCoinBaseIn),nHeight(nHeightIn) {}
49	
50	    void Clear() {
51	        out.SetNull();
52	        fCoinBase = false;
53	        nHeight = 0;
54	    }
55	
56	    //! empty constructor
57	    Coin() : fCoinBase(false), nHeight(0) { }
58	
59	    bool IsCoinBase() const {
60	        return fCoinBase;
61	    }
62	
63	    template<typename Stream>
64	    void Serialize(Stream &s) const {
65	        assert(!IsSpent());
66	        uint32_t code{(uint32_t{nHeight} << 1) | uint32_t{fCoinBase}};
67	        ::Serialize(s, VARINT(code));
68	        ::Serialize(s, Using<TxOutCompression>(out));
69	    }
70	
71	    template<typename Stream>
72	    void Unserialize(Stream &s) {
73	        uint32_t code = 0;
74	        ::Unserialize(s, VARINT(code));
75	        nHeight = code >> 1;
76	        fCoinBase = code & 1;
77	        ::Unserialize(s, Using<TxOutCompression>(out));
78	    }
79	
80	    /** Either this coin never existed (see e.g. coinEmpty in coins.cpp), or it
81	      * did exist and has been spent.
82	      */
83	    bool IsSpent() const {
84	        return out.IsNull();
85	    }
86	
87	    size_t DynamicMemoryUsage() const {
88	        return memusage::DynamicUsage(out.scriptPubKey);
89	    }
90	};
